	System.out.println("Core Java");
	
	//PRIMITIVE DATATYPES:- int,double,float,long,boolean,short
	//means type of data values are defined
	
	//NON PRIMITIVE DATTYPE:- string,arrays
	//means type of data values are not defined
	//we can store any kind of values
	
	int a=4,b=5;//initialization
	int c,d;//declaration
	
